"use client";

import React, { createContext, useContext, useEffect, useState, useCallback, useRef } from "react";
import { io, Socket } from "socket.io-client";
import { useAuth } from "@/context/AuthContext";

interface SocketContextData {
  socket: Socket | null;
  isConnected: boolean;
  onlineUsers: Set<string>;
  isUserOnline: (userId: number | string) => boolean;
}

const SocketContext = createContext<SocketContextData>({
  socket: null,
  isConnected: false,
  onlineUsers: new Set(),
  isUserOnline: () => false,
});

export const useSocket = () => useContext(SocketContext);

export const SocketProvider = ({ children }: { children: React.ReactNode }) => {
  const { user } = useAuth();
  const userId = user?.id;

  const [socket, setSocket] = useState<Socket | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState<Set<string>>(new Set());

  // Keep a ref so we can access the current socket in cleanup without stale closure
  const socketRef = useRef<Socket | null>(null);
  const failCountRef = useRef(0);

  const isUserOnline = useCallback(
    (id: number | string) => onlineUsers.has(id.toString()),
    [onlineUsers]
  );

  useEffect(() => {
    // Disconnect and reset if not authenticated
    if (!userId) {
      if (socketRef.current) {
        socketRef.current.disconnect();
        socketRef.current = null;
        setSocket(null);
        setIsConnected(false);
      }
      setOnlineUsers(new Set());
      return;
    }

    // Don't create a second socket if one is already open for this user
    if (socketRef.current?.connected) return;

    // If we've already failed multiple times, stop trying
    if (failCountRef.current >= 3) return;

    // IMPORTANT: Since the app is running on Hostinger without server.js,
    // WebSockets are unsupported. We actively bypass the connection logic
    // to prevent continuous 404 Not Found errors in the browser console.
    // The application will automatically rely on the HTTP polling fallback we built.
    return;

    /*
    const socketInstance = io(window.location.origin, {
      path: "/socket.io/",
      transports: ["polling", "websocket"],
      upgrade: true,
      reconnectionAttempts: 3,
      reconnectionDelay: 3000,
      reconnectionDelayMax: 10000,
      timeout: 8000,
      forceNew: false,
      autoConnect: true,
    });

    socketRef.current = socketInstance;
    setSocket(socketInstance);

    socketInstance.on("connect", () => {
      failCountRef.current = 0; // Reset fail count on success
      setIsConnected(true);
      socketInstance.emit("register", userId);
      console.log("[Socket] Connected, registered userId:", userId);
    });

    socketInstance.on("disconnect", (reason) => {
      setIsConnected(false);
      console.log("[Socket] Disconnected:", reason);
    });

    socketInstance.on("connect_error", () => {
      failCountRef.current++;
      // After 3 failures, stop reconnecting silently — server.js likely isn't running
      if (failCountRef.current >= 3) {
        socketInstance.disconnect();
        console.log("[Socket] Server unavailable — real-time features disabled. App continues with polling.");
      }
    });

    // Online presence
    socketInstance.on("online_users", (userIds: string[]) => {
      setOnlineUsers(new Set(userIds));
    });

    socketInstance.on("user_online", (id: string) => {
      setOnlineUsers((prev) => {
        const next = new Set(prev);
        next.add(id);
        return next;
      });
    });

    socketInstance.on("user_offline", (id: string) => {
      setOnlineUsers((prev) => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
    });

    */

    return () => {
      /*
      socketInstance.disconnect();
      */
      socketRef.current = null;
      setSocket(null);
      setIsConnected(false);
    };
  }, [userId]);

  return (
    <SocketContext.Provider value={{ socket, isConnected, onlineUsers, isUserOnline }}>
      {children}
    </SocketContext.Provider>
  );
};
